function limpiar_numero(valor) {
    try {
        if (valor === undefined || valor === null || valor.trim() === '') return 0.0;
        let num = parseFloat(String(valor).replace(',', '.'));
        return isNaN(num) ? 0.0 : num;
    } catch(e) {
        return 0.0;
    }
}

let items = $input.all();
let inventario = [];

for (let item of items) {
    let linea = item.json.LineaInventario;
    if (!linea) continue;
    let cols = linea.split('|');
    if (cols.length < 33) continue;

    inventario.push({
        "codprod": String(cols[1]).trim(),
        "barra": String(cols[0]).trim(),
        "desprod": String(cols[2]).trim(),
        "tipo": String(cols[3]).trim(),
        "costo": limpiar_numero(cols[25]),
        "regulado": String(cols[5]).trim(),
        "precio1": limpiar_numero(cols[7]),
        "iva": limpiar_numero(cols[4]),
        "oferta": limpiar_numero(cols[11]),
        "bulto": parseInt(limpiar_numero(cols[9])),
        "dctoneto": limpiar_numero(cols[20]),
        "psugerido": limpiar_numero(cols[14]),
        "ubicacion": String(cols[26]).trim(),
        "fechafalla": String(cols[17]).trim(),
        "fecvence": String(cols[22]).trim(),
        "pactivo": String(cols[24]).trim(),
        "pgris": limpiar_numero(cols[15]),
        "marca": String(cols[23]).trim(),
        "subgrupo": String(cols[31]).trim(),
        "categoria": String(cols[30]).trim(),
        "molecula": String(cols[32]).trim(),
        "codprov": String(cols[6]).trim(),
        "upre": String(cols[12]).trim(),
        "ppre": limpiar_numero(cols[13]),
        "cantidad": parseInt(limpiar_numero(cols[8]))
    });
}

// Split into batches of 1000
let batches = [];
let batchSize = 1000;
let totalBatches = Math.ceil(inventario.length / batchSize);

for (let i = 0; i < inventario.length; i += batchSize) {
    let chunk = inventario.slice(i, i + batchSize);

    batches.push({
        json: {
            licencia: "VEISACO0000100100845",
            serial: "NG5626W1019110S390",
            codisb: "008376238",
            datos: JSON.stringify(chunk),
            _batchInfo: {
                number: (i / batchSize) + 1,
                total: totalBatches,
                size: chunk.length
            }
        }
    });
}

return batches;
